<script setup lang="ts">import {ref} from 'vue';import {api} from '../../api';import {useMerchantContext} from '../../stores/merchantContext';const c=useMerchantContext();const report=ref<any>(null);const loading=ref(false);async function run(){loading.value=true;try{report.value=await api('/formal-diagnostic-runs',{method:'POST',body:JSON.stringify({merchantId:c.merchant.value!.id})})}finally{loading.value=false}}</script>
<template><section class="module-page"><div class="module-heading"><div><span class="eyebrow">DIAGNOSIS & STRATEGY</span><h2>诊断与策略</h2><p>运行正式GEO诊断，查看评分、竞争品牌和Gap建议。</p></div><el-button type="primary" :loading="loading" :disabled="c.data.prompts.length<20||!c.data.evidence.length" @click="run">生成正式报告</el-button></div><div class="module-columns"><div class="panel"><h3>竞争品牌（{{c.data.competitors.length}}）</h3><div v-if="!c.data.competitors.length" class="empty-inline">尚未配置竞争品牌。</div><div v-for="competitor in c.data.competitors" :key="competitor.id" class="data-row"><b>{{competitor.name}}</b><small>{{competitor.aliases||'未填写别名'}}</small></div></div><div class="panel"><h3>执行Gap任务（{{c.data.tasks.length}}）</h3><p class="muted-copy">报告生成后，从Gap派生的30天任务会在执行中心继续处理。</p><router-link :to="`/merchants/${c.merchant.value?.id}/execution`"><el-button>进入执行中心</el-button></router-link></div></div><div v-if="report" class="report-summary"><strong>{{report.score??'—'}}</strong><span>/ 100 · {{report.evidenceCount}} 条证据 · {{report.questionCount}} 个问题</span><pre>{{report.reportMarkdown}}</pre></div><div v-else class="empty-state"><h3>尚未在本次会话生成报告</h3><p>正式报告只使用非演示真实证据；完成后可在执行中心生成30天任务。</p></div></section></template>
